import numpy as np

class MultiTaskModel:
    def __init__(self, n_shared_params, n_tasks, n_head_params):
        self.n_shared = n_shared_params
        self.n_tasks = n_tasks
        self.n_head = n_head_params

        # Shared encoder
        self.shared_params = np.random.randn(n_shared_params) * 0.1

        # Task-specific heads
        self.task_heads = {
            i: np.random.randn(n_head_params) * 0.1
            for i in range(n_tasks)
        }

    def shared_encoder(self, x):
        result = x
        for p in self.shared_params:
            result = np.sin(p * result)
        return result

    def task_head(self, features, task_id):
        result = features
        for p in self.task_heads[task_id]:
            result = np.tanh(p * result)
        return result

    def forward(self, x, task_id):
        features = self.shared_encoder(x)
        return self.task_head(features, task_id)

