import numpy as np

class MultiTaskModel:
    def __init__(self, n_shared_params, n_tasks, n_head_params):
        self.n_shared = n_shared_params
        self.n_tasks = n_tasks
        self.n_head = n_head_params
        self.shared_params = np.random.randn(n_shared_params) * 0.1
        self.task_heads = {
            i: np.random.randn(n_head_params) * 0.1
            for i in range(n_tasks)
        }

    def forward(self, x, task_id):
        result = x
        for p in self.shared_params:
            result = np.sin(p * result)
        for p in self.task_heads[task_id]:
            result = np.tanh(p * result)
        return result

    def get_all_params(self):
        params = list(self.shared_params)
        for t in range(self.n_tasks):
            params.extend(self.task_heads[t])
        return np.array(params)

    def set_all_params(self, params):
        self.shared_params = params[:self.n_shared]
        idx = self.n_shared
        for t in range(self.n_tasks):
            self.task_heads[t] = params[idx:idx + self.n_head]
            idx += self.n_head

def multi_task_loss(model, task_datasets, task_weights=None):
    if task_weights is None:
        task_weights = {t: 1.0 / len(task_datasets) for t in task_datasets}

    total_loss = 0
    for task_id, (x_data, y_data) in task_datasets.items():
        task_loss = 0
        for x, y in zip(x_data, y_data):
            pred = model.forward(x, task_id)
            task_loss += (pred - y) ** 2
        task_loss /= len(x_data)
        total_loss += task_weights[task_id] * task_loss

    return total_loss

def train_multi_task(model, task_datasets, epochs=50, lr=0.1):
    print("Multi-Task Training:")
    all_params = model.get_all_params()

    for epoch in range(epochs):
        grad = np.zeros_like(all_params)

        for task_id, (x_data, y_data) in task_datasets.items():
            for x, y in zip(x_data, y_data):
                for i in range(len(all_params)):
                    eps = 0.01
                    all_params[i] += eps
                    model.set_all_params(all_params)
                    loss_plus = (model.forward(x, task_id) - y) ** 2
                    all_params[i] -= eps
                    model.set_all_params(all_params)
                    loss = (model.forward(x, task_id) - y) ** 2

                    grad[i] += (loss_plus - loss) / eps

        all_params -= lr * grad / (len(task_datasets) * len(x_data))
        model.set_all_params(all_params)

        if epoch % 10 == 0:
            loss = multi_task_loss(model, task_datasets)
            print(f"  Epoch {epoch}: Loss = {loss:.4f}")

    return model

# Test
np.random.seed(42)
model = MultiTaskModel(n_shared_params=4, n_tasks=2, n_head_params=2)

x = np.linspace(-2, 2, 15)
task_datasets = {
    0: (x, np.sin(x)),
    1: (x, np.cos(x))
}

trained = train_multi_task(model, task_datasets, epochs=40)

import numpy as np

def uniform_weights(n_tasks):
    return {i: 1.0 / n_tasks for i in range(n_tasks)}

def loss_scale_weights(task_losses):
    # Inverse proportional to loss
    inverse = {t: 1.0 / (loss + 1e-10) for t, loss in task_losses.items()}
    total = sum(inverse.values())
    return {t: w / total for t, w in inverse.items()}

def dynamic_weights(task_losses, prev_losses=None, alpha=0.5):
    n_tasks = len(task_losses)
    weights = {t: 1.0 for t in task_losses}

    if prev_losses is not None:
        for task_id in task_losses:
            curr = task_losses[task_id]
            prev = prev_losses.get(task_id, curr)
            improvement = prev - curr

            if improvement < 0:  # Getting worse
                weights[task_id] *= (1 + alpha)
            elif improvement < 0.01:  # Slow improvement
                weights[task_id] *= (1 + alpha * 0.5)

    total = sum(weights.values())
    return {t: w / total for t, w in weights.items()}

# Test
np.random.seed(42)
print("Loss Balancing:")
print("=" * 40)

task_losses = {0: 0.1, 1: 1.5, 2: 0.5}

print(f"\nTask losses: {task_losses}")

print(f"\n1. Uniform weights:")
for t, w in uniform_weights(3).items():
    print(f"   Task {t}: {w:.3f}")

print(f"\n2. Loss scale weights:")
for t, w in loss_scale_weights(task_losses).items():
    print(f"   Task {t}: {w:.3f}")

print(f"\n3. Dynamic weights (first iteration):")
for t, w in dynamic_weights(task_losses).items():
    print(f"   Task {t}: {w:.3f}")

# Simulate iteration
print(f"\n4. Dynamic weights (after improvement):")
prev_losses = {0: 0.15, 1: 1.6, 2: 0.6}  # Task 1 improved most
for t, w in dynamic_weights(task_losses, prev_losses).items():
    print(f"   Task {t}: {w:.3f}")

import numpy as np

def evaluate_multi_task(model, test_datasets):
    per_task = {}

    for task_id, (x_test, y_test) in test_datasets.items():
        predictions = [model.forward(x, task_id) for x in x_test]
        mse = np.mean((np.array(predictions) - y_test) ** 2)

        per_task[task_id] = {
            'mse': mse,
            'rmse': np.sqrt(mse)
        }

    avg_mse = np.mean([r['mse'] for r in per_task.values()])

    return {
        'per_task': per_task,
        'avg_mse': avg_mse,
        'avg_rmse': np.sqrt(avg_mse)
    }

def compare_to_baselines(mtl_results, stl_results):
    comparison = {}

    for task_id in mtl_results['per_task']:
        mtl_mse = mtl_results['per_task'][task_id]['mse']
        stl_mse = stl_results.get(task_id, mtl_mse)

        if stl_mse > 0:
            improvement = (stl_mse - mtl_mse) / stl_mse * 100
        else:
            improvement = 0

        comparison[task_id] = {
            'mtl_mse': mtl_mse,
            'stl_mse': stl_mse,
            'improvement': improvement,
            'mtl_better': improvement > 0
        }

    avg_improvement = np.mean([c['improvement'] for c in comparison.values()])

    return {
        'per_task': comparison,
        'avg_improvement': avg_improvement
    }

# Test
np.random.seed(42)
print("Multi-Task Evaluation:")
print("=" * 40)

class DummyModel:
    def forward(self, x, task_id):
        if task_id == 0:
            return np.sin(x) + 0.1  # Slight error
        else:
            return np.cos(x)  # Perfect

model = DummyModel()
x = np.linspace(-1, 1, 10)
test_datasets = {
    0: (x, np.sin(x)),
    1: (x, np.cos(x))
}

print("\n1. Evaluate MTL model:")
results = evaluate_multi_task(model, test_datasets)
for t, r in results['per_task'].items():
    print(f"   Task {t}: MSE = {r['mse']:.4f}")
print(f"   Average MSE: {results['avg_mse']:.4f}")

print("\n2. Compare to baselines:")
stl_results = {0: 0.02, 1: 0.005}  # Single-task baselines
comp = compare_to_baselines(results, stl_results)
for t, c in comp['per_task'].items():
    status = "MTL better" if c['mtl_better'] else "STL better"
    print(f"   Task {t}: {c['improvement']:.1f}% ({status})")
print(f"   Average improvement: {comp['avg_improvement']:.1f}%")
